INSERT INTO public.nights (id, name, description, type, levels, bringer, schedule, venue, pricing, how_to_book, socials, status, last_verified) VALUES
  ('angel-comedy-bill-murray', 'Angel Comedy', 'One of London''s longest-running free comedy nights. A mixed bill of new and established acts in a proper pub setting. Always a full room, always a good vibe.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":1,"startTime":"20:00"}'::jsonb, '{"id":"bill-murray","name":"The Bill Murray","address":"39 Queen''s Head St, London N1 8NQ","area":"Islington","nearestStation":"Angel","location":{"lat":51.5354,"lng":-0.1036}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free entry, no booking needed","performers":"Email angelcomedyclub@gmail.com to get on the bill"}'::jsonb, '{"website":"https://angelcomedy.co.uk","instagram":"https://instagram.com/angelcomedyclub","facebook":"https://facebook.com/angelcomedyclub"}'::jsonb, 'active', '2026-05-20'),
  ('downstairs-kings-head', 'Downstairs at The King''s Head', 'North London''s home for new comedy. A bringer night in a cosy basement venue. Great for brand-new acts and brave audiences.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":true,"count":2,"note":"Bring 2 paying audience members"}'::jsonb, '{"frequency":"weekly","weekday":4,"startTime":"19:30"}'::jsonb, '{"id":"kings-head-crouch-end","name":"The King''s Head","address":"2 Crouch End Hill, London N8 8AA","area":"Crouch End","nearestStation":"Finsbury Park","location":{"lat":51.5814,"lng":-0.1212}}'::jsonb, '{"entry":"£5","performerPay":"None"}'::jsonb, '{"audience":"Pay on the door","performers":"Sign up sheet at the bar from 7pm"}'::jsonb, '{}'::jsonb, 'active', '2026-05-15'),
  ('comedy-cavendish-arms', 'ACMS at The Cavendish Arms', 'A welcoming open-mic run by the Alternative Comedy Memorial Society. All styles welcome, supportive crowd, no bringer.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":0,"startTime":"19:00"}'::jsonb, '{"id":"cavendish-arms","name":"The Cavendish Arms","address":"128 Hartington Rd, London SW8 2HJ","area":"Stockwell","nearestStation":"Stockwell","location":{"lat":51.4717,"lng":-0.1233}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free entry","performers":"Turn up before 7pm to get a slot"}'::jsonb, '{"facebook":"https://facebook.com/alternativecomedymemorialsociety"}'::jsonb, 'active', '2026-06-01'),
  ('banana-cabaret-balham', 'Banana Cabaret', 'One of the best weekly club nights in South London. A proper four-act bill with a headliner you''d pay to see at the Hammersmith. Been running since 1993.', 'showcase', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":6,"startTime":"20:30"}'::jsonb, '{"id":"bedford-balham","name":"The Bedford","address":"77 Bedford Hill, London SW12 9HD","area":"Balham","nearestStation":"Balham","location":{"lat":51.4435,"lng":-0.153}}'::jsonb, '{"entry":"£15","performerPay":"Paid"}'::jsonb, '{"audience":"Book online via their website","performers":"Promoter-only bookings"}'::jsonb, '{"website":"https://bananacabaret.co.uk","instagram":"https://instagram.com/bananacabaret"}'::jsonb, 'active', '2026-05-28'),
  ('backyard-comedy-bethnal-green', 'Backyard Comedy Club', 'East London institution in a purpose-built comedy club. Weekly Saturday show with a proper bill — MC, two supports, headliner. Good bar, good crowd.', 'showcase', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":6,"startTime":"20:00"}'::jsonb, '{"id":"backyard-bethnal-green","name":"Backyard Comedy Club","address":"231 Cambridge Heath Rd, London E2 0EL","area":"Bethnal Green","nearestStation":"Bethnal Green","location":{"lat":51.5279,"lng":-0.0582}}'::jsonb, '{"entry":"£12","performerPay":"Paid"}'::jsonb, '{"audience":"Book via Eventbrite","performers":"Promoter-only bookings"}'::jsonb, '{"website":"https://backyardcomedyclub.co.uk","instagram":"https://instagram.com/backyardcomedyclub"}'::jsonb, 'active', '2026-05-30'),
  ('the-comedy-store-london', 'The Comedy Store', 'The granddaddy of London comedy. The Cutting Edge (Tuesday) is sharp political improv; the weekend shows are top-tier stand-up. A London institution since 1979.', 'pro', ARRAY['pro']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":2,"startTime":"20:00","note":"Also Fri & Sat — check website"}'::jsonb, '{"id":"comedy-store-london","name":"The Comedy Store","address":"1a Oxendon St, London SW1Y 4EE","area":"Westminster","nearestStation":"Piccadilly Circus","location":{"lat":51.5094,"lng":-0.1305}}'::jsonb, '{"entry":"£20","performerPay":"Paid"}'::jsonb, '{"audience":"Book via their website","performers":"Invitation only"}'::jsonb, '{"website":"https://thecomedystore.co.uk","instagram":"https://instagram.com/thecomedystorelondon"}'::jsonb, 'active', '2026-06-01'),
  ('99-club-leicester-sq', '99 Club Leicester Square', 'Mid-week club night in the heart of the West End. Usually a four-act bill, decent headline slot. Good for spotting acts on the way up.', 'showcase', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":3,"startTime":"20:00"}'::jsonb, '{"id":"the-venue-leicester-sq","name":"The Venue","address":"99 Leicester Square, London WC2H 7LH","area":"Soho","nearestStation":"Leicester Square","location":{"lat":51.5108,"lng":-0.1312}}'::jsonb, '{"entry":"£10","performerPay":"Paid"}'::jsonb, '{"audience":"Book online, tickets cheaper in advance","performers":"Promoter bookings"}'::jsonb, '{"website":"https://99clubcomedy.com"}'::jsonb, 'active', '2026-05-22'),
  ('we-are-funny-project-brixton', 'We Are Funny Project', 'A Monday night open-mic for absolute beginners. Genuinely zero-judgment, zero-bringer. Five minutes, a supportive room, and a cheap pint. The best place to do your first ever gig.', 'open-mic', ARRAY['new']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":1,"startTime":"19:30"}'::jsonb, '{"id":"prince-of-wales-brixton","name":"Prince of Wales","address":"467-469 Brixton Rd, London SW9 8HH","area":"Brixton","nearestStation":"Brixton","location":{"lat":51.4622,"lng":-0.115}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free, just turn up","performers":"Sign up online at wearefunnyproject.com"}'::jsonb, '{"website":"https://wearefunnyproject.com","instagram":"https://instagram.com/wearefunnyproject"}'::jsonb, 'active', '2026-06-05'),
  ('hen-chickens-highbury', 'Hen & Chickens Comedy', 'Upstairs-pub theatre with a long history of launching careers. Regular showcase nights with a proper stage and decent sound. The booking queue fills up fast.', 'showcase', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":1,"startTime":"20:00"}'::jsonb, '{"id":"hen-chickens","name":"Hen & Chickens Theatre","address":"109 St Paul''s Rd, London N1 2NA","area":"Highbury","nearestStation":"Highbury & Islington","location":{"lat":51.5529,"lng":-0.0996}}'::jsonb, '{"entry":"£10","performerPay":"Expenses"}'::jsonb, '{"audience":"Book via their website","performers":"Email the booker"}'::jsonb, '{"website":"https://henandchickens.com"}'::jsonb, 'active', '2026-05-10'),
  ('up-the-creek-greenwich', 'Up The Creek', 'South-east London''s most famous comedy club. Notoriously rowdy crowd on Fridays — acts who can handle Up The Creek can handle anything. Headliners you''ve seen on telly.', 'showcase', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":5,"startTime":"20:00","note":"Also Saturday shows — check website"}'::jsonb, '{"id":"up-the-creek","name":"Up The Creek","address":"302 Creek Rd, London SE10 9SW","area":"Greenwich","nearestStation":"Greenwich","location":{"lat":51.4794,"lng":-0.0118}}'::jsonb, '{"entry":"£15","performerPay":"Paid"}'::jsonb, '{"audience":"Book via their website","performers":"Invitation only"}'::jsonb, '{"website":"https://up-the-creek.com","instagram":"https://instagram.com/upthecreekcomedy"}'::jsonb, 'active', '2026-05-25'),
  ('hot-pickle-hackney', 'Hot Pickle Comedy', 'A fortnightly mixed-bill showcase in a Hackney pub. Curated lineup, small room, close-up comedy. Exactly the kind of night where you discover your new favourite act.', 'mixed', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"biweekly","weekday":3,"startTime":"20:00"}'::jsonb, '{"id":"prince-of-wales-hackney","name":"Prince of Wales","address":"158 Lea Bridge Rd, London E5 9QB","area":"Hackney","nearestStation":"Clapton","location":{"lat":51.5535,"lng":-0.0508}}'::jsonb, '{"entry":"£8","performerPay":"Expenses"}'::jsonb, '{"audience":"Book via Eventbrite","performers":"Email hotpicklecomedy@gmail.com"}'::jsonb, '{"instagram":"https://instagram.com/hotpicklecomedy"}'::jsonb, 'active', '2026-04-20'),
  ('two-brewers-comedy-clapham', 'Two Brewers Comedy Night', 'Tuesday night open-mic above a Clapham pub. No bringer, no nonsense. Great for acts building a set and audiences who like discovering comics before they''re famous.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":2,"startTime":"20:00"}'::jsonb, '{"id":"two-brewers-clapham","name":"Two Brewers","address":"114 Clapham High St, London SW4 7UJ","area":"Clapham","nearestStation":"Clapham Common","location":{"lat":51.4615,"lng":-0.1383}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free entry","performers":"Email the organiser to get a slot"}'::jsonb, '{}'::jsonb, 'active', '2026-05-05'),
  ('chuckle-busters-herne-hill', 'Chuckle Busters', 'Monthly showcase in a beautiful South London pub. Small enough to feel intimate, polished enough to attract proper headliners. Audience is always warm.', 'showcase', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"monthly","weekday":6,"startTime":"19:30"}'::jsonb, '{"id":"florence-herne-hill","name":"The Florence","address":"131-133 Dulwich Rd, London SE24 0NG","area":"Herne Hill","nearestStation":"Herne Hill","location":{"lat":51.4524,"lng":-0.0962}}'::jsonb, '{"entry":"£10","performerPay":"Expenses"}'::jsonb, '{"audience":"Book via Eventbrite or pay on the door","performers":"Email chucklebusters@gmail.com"}'::jsonb, '{"instagram":"https://instagram.com/chucklebusters","facebook":"https://facebook.com/chucklebusters"}'::jsonb, 'active', '2026-05-18'),
  ('black-heart-comedy-camden', 'The Black Heart Open Mic', 'A bringer open-mic in a Camden metal pub. Unconventional crowd keeps acts on their toes. One of those nights where you either die or become a lot better.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":true,"count":3,"note":"Bring 3 paying guests"}'::jsonb, '{"frequency":"weekly","weekday":3,"startTime":"19:30"}'::jsonb, '{"id":"black-heart-camden","name":"The Black Heart","address":"3 Greenland Pl, London NW1 0AP","area":"Camden","nearestStation":"Camden Town","location":{"lat":51.5393,"lng":-0.1457}}'::jsonb, '{"entry":"£5","performerPay":"None"}'::jsonb, '{"audience":"Pay on the door","performers":"Email to book a slot in advance"}'::jsonb, '{}'::jsonb, 'active', '2026-04-10'),
  ('laugh-out-london-brixton', 'Laugh Out London', 'A Thursday night showcase in Brixton with a focus on diverse lineups. Fast-moving, well-MC''d, great atmosphere. Always sells out — book early.', 'showcase', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":4,"startTime":"20:00"}'::jsonb, '{"id":"dogstar-brixton","name":"The Dogstar","address":"389 Coldharbour Ln, London SW9 8LQ","area":"Brixton","nearestStation":"Brixton","location":{"lat":51.4643,"lng":-0.1133}}'::jsonb, '{"entry":"£12","performerPay":"Paid"}'::jsonb, '{"audience":"Book via laughoutlondon.com — sells out quickly","performers":"Apply via their website"}'::jsonb, '{"website":"https://laughoutlondon.co.uk","instagram":"https://instagram.com/laughoutlondon"}'::jsonb, 'active', '2026-06-01'),
  ('comedy-virgins-balham', 'Comedy Virgins', 'The original first-timers night. Run with warmth and zero judgment. If you''ve never done stand-up before, this is the night you do it. Genuinely life-changing for some people.', 'open-mic', ARRAY['new']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":2,"startTime":"19:30"}'::jsonb, '{"id":"balham-bowls-club","name":"Balham Bowls Club","address":"7-9 Ramsden Rd, London SW12 8QX","area":"Balham","nearestStation":"Balham","location":{"lat":51.4431,"lng":-0.1521}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free entry","performers":"Sign up at comedyvirgins.com"}'::jsonb, '{"website":"https://comedyvirgins.com","instagram":"https://instagram.com/comedyvirgins"}'::jsonb, 'active', '2026-06-03'),
  ('free-comedy-the-hob', 'Free Comedy at The Hob', 'Monday open-mic in Forest Hill with no bringer and no entry fee. Small but enthusiastic crowd. Run with care — acts get proper feedback after the show.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":1,"startTime":"20:00"}'::jsonb, '{"id":"the-hob-forest-hill","name":"The Hob","address":"1-3 Perry Vale, London SE23 2NE","area":"Forest Hill","nearestStation":"Forest Hill","location":{"lat":51.4361,"lng":-0.0561}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free, walk in","performers":"Email to get on the list"}'::jsonb, '{}'::jsonb, 'active', '2026-04-25'),
  ('cosmic-comedy-shepherds-bush', 'Cosmic Comedy', 'Monthly showcase in West London with a reputation for booking acts just before they break. Good mix of styles, enthusiastic crowd, excellent value.', 'showcase', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"monthly","weekday":5,"startTime":"20:00"}'::jsonb, '{"id":"bush-theatre","name":"The Defector''s Weld","address":"170 Uxbridge Rd, London W12 8AA","area":"Shepherd''s Bush","nearestStation":"Shepherd''s Bush","location":{"lat":51.5042,"lng":-0.2267}}'::jsonb, '{"entry":"£10","performerPay":"Expenses"}'::jsonb, '{"audience":"Book via Eventbrite","performers":"Email cosmiccomedy@gmail.com"}'::jsonb, '{"instagram":"https://instagram.com/cosmiccomedylondon"}'::jsonb, 'active', '2026-05-12'),
  ('smoke-comedy-hackney', 'Smoke Comedy', 'Monthly showcase from the team behind some of the best mid-size rooms in London. Strong lineups, intimate venue, always over-subscribed.', 'showcase', ARRAY['pro']::text[], '{"required":false}'::jsonb, '{"frequency":"monthly","weekday":4,"startTime":"20:00"}'::jsonb, '{"id":"oslo-hackney","name":"Oslo","address":"1A Amhurst Rd, London E8 1LL","area":"Hackney","nearestStation":"Hackney Central","location":{"lat":51.5458,"lng":-0.0609}}'::jsonb, '{"entry":"£14","performerPay":"Paid"}'::jsonb, '{"audience":"Book via their website — sells out weeks in advance","performers":"Invitation only"}'::jsonb, '{"instagram":"https://instagram.com/smokecomedylondon","website":"https://smokecomedylondon.com"}'::jsonb, 'active', '2026-05-30'),
  ('fun-machine-peckham', 'The Fun Machine', 'Peckham''s loudest, most chaotic monthly comedy night. Mixed bill format, experimental acts welcome, crowd has a high tolerance for weirdness. Bring your friends.', 'mixed', ARRAY['new','experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"monthly","weekday":6,"startTime":"20:00"}'::jsonb, '{"id":"bussey-building-peckham","name":"The Bussey Building","address":"133 Rye Ln, London SE15 4ST","area":"Peckham","nearestStation":"Peckham Rye","location":{"lat":51.471,"lng":-0.068}}'::jsonb, '{"entry":"£8","performerPay":"None"}'::jsonb, '{"audience":"Tickets via Resident Advisor or pay on door if available","performers":"DM on Instagram"}'::jsonb, '{"instagram":"https://instagram.com/funmachinecomedy"}'::jsonb, 'active', '2026-05-01'),
  ('amused-moose-soho', 'Amused Moose Soho', 'Monthly showcase in the heart of Soho from one of London''s most respected comedy promoters. If you''re seeing someone here, they''re the real deal.', 'showcase', ARRAY['pro']::text[], '{"required":false}'::jsonb, '{"frequency":"monthly","weekday":5,"startTime":"20:00","note":"Check website for exact dates"}'::jsonb, '{"id":"soho-theatre","name":"Soho Theatre","address":"21 Dean St, London W1D 3NE","area":"Soho","nearestStation":"Tottenham Court Road","location":{"lat":51.5141,"lng":-0.133}}'::jsonb, '{"entry":"£16","performerPay":"Paid"}'::jsonb, '{"audience":"Book via Soho Theatre website","performers":"Invitation only"}'::jsonb, '{"website":"https://amusedmoose.com"}'::jsonb, 'active', '2026-04-15'),
  ('comedy-at-sekforde-clerkenwell', 'Comedy at The Sekforde', 'Tuesday open-mic in a proper Clerkenwell boozer. Regulars are a mix of office workers and circuit acts running new material. Cosy room, attentive crowd.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":2,"startTime":"20:00"}'::jsonb, '{"id":"sekforde-arms","name":"The Sekforde Arms","address":"34 Sekforde St, London EC1R 0HA","area":"Clerkenwell","nearestStation":"Farringdon","location":{"lat":51.5238,"lng":-0.1068}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free entry","performers":"Sign up sheet on the night from 7:30pm"}'::jsonb, '{}'::jsonb, 'active', '2026-05-20'),
  ('phoenix-comedy-cavendish', 'The Phoenix Comedy Night', 'Long-running Monday open-mic in a West End pub theatre. Mix of circuit veterans sharpening new material and first-timers trying it for the first time.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":1,"startTime":"20:00"}'::jsonb, '{"id":"phoenix-artist-club","name":"Phoenix Artist Club","address":"1 Phoenix St, London WC2H 8BU","area":"Covent Garden","nearestStation":"Covent Garden","location":{"lat":51.5131,"lng":-0.1273}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free, members only — but membership is easy to get","performers":"Sign up at the bar before 8pm"}'::jsonb, '{}'::jsonb, 'active', '2026-05-08'),
  ('comedy-grosvenor-stockwell', 'Comedy at The Grosvenor', 'Wednesday night bringer open-mic in Stockwell. Intimate room, no frills, direct feedback. A classic bringer setup — bring your mates, die in front of them, repeat.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":true,"count":2,"note":"Bring 2 paying guests (£3 each)"}'::jsonb, '{"frequency":"weekly","weekday":3,"startTime":"20:00"}'::jsonb, '{"id":"grosvenor-stockwell","name":"The Grosvenor","address":"1 Sidney Rd, London SW9 0TP","area":"Stockwell","nearestStation":"Stockwell","location":{"lat":51.4727,"lng":-0.123}}'::jsonb, '{"entry":"£3","performerPay":"None"}'::jsonb, '{"audience":"Pay on the door","performers":"Email to book a slot"}'::jsonb, '{}'::jsonb, 'active', '2026-04-28'),
  ('covent-garden-comedy-club', 'Covent Garden Comedy Club', 'Centrally located, easy to find, and always a quality lineup. Tourist-friendly without being dumbed down. A reliable Friday night in the West End.', 'showcase', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":5,"startTime":"20:30"}'::jsonb, '{"id":"museum-tavern-covent-garden","name":"The Museum Tavern","address":"49 Great Russell St, London WC1B 3BA","area":"Covent Garden","nearestStation":"Holborn","location":{"lat":51.5184,"lng":-0.1256}}'::jsonb, '{"entry":"£12","performerPay":"Paid"}'::jsonb, '{"audience":"Book online via Eventbrite","performers":"Email the promoter"}'::jsonb, '{"instagram":"https://instagram.com/coventgardencomedy"}'::jsonb, 'active', '2026-05-15'),
  ('short-form-improv-hoxton', 'Short Form Improv Night', 'Weekly improv jam in Hoxton. No scripts, no safety net. Great for improvisers to practice and audiences to watch things go gloriously wrong.', 'mixed', ARRAY['new','experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":1,"startTime":"19:30"}'::jsonb, '{"id":"hoxton-bar-kitchen","name":"Hoxton Bar & Kitchen","address":"2-4 Hoxton Square, London N1 6NU","area":"Shoreditch","nearestStation":"Old Street","location":{"lat":51.5262,"lng":-0.0829}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free","performers":"Email to join the rotating cast"}'::jsonb, '{}'::jsonb, 'active', '2026-03-20'),
  ('comedy-hideaway-streatham', 'The Comedy Hideaway', 'South London''s most underrated comedy club. A proper room above a pub, good sound, and the promoter has an eye for talent. The kind of night that spawns regulars.', 'showcase', ARRAY['experienced','pro']::text[], '{"required":false}'::jsonb, '{"frequency":"monthly","weekday":6,"startTime":"20:00"}'::jsonb, '{"id":"hideaway-streatham","name":"The Hideaway","address":"2 Vining St, London SW9 8QA","area":"Streatham","nearestStation":"Streatham","location":{"lat":51.431,"lng":-0.1259}}'::jsonb, '{"entry":"£12","performerPay":"Paid"}'::jsonb, '{"audience":"Book via their website","performers":"Email the promoter"}'::jsonb, '{"website":"https://thehideaway.co.uk","instagram":"https://instagram.com/comedyhideaway"}'::jsonb, 'active', '2026-04-30'),
  ('noodle-comedy-shoreditch', 'Noodle Comedy', 'A quirky mid-week showcase in Shoreditch with a leaning toward alternative and character comedy. Not your standard club night — expect the unexpected.', 'mixed', ARRAY['experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"biweekly","weekday":3,"startTime":"20:00"}'::jsonb, '{"id":"noodle-bar-shoreditch","name":"Rich Mix","address":"35-47 Bethnal Green Rd, London E1 6LA","area":"Shoreditch","nearestStation":"Shoreditch High Street","location":{"lat":51.5229,"lng":-0.0758}}'::jsonb, '{"entry":"£9","performerPay":"Expenses"}'::jsonb, '{"audience":"Book via Rich Mix website","performers":"Apply via Instagram"}'::jsonb, '{"instagram":"https://instagram.com/noodlecomedy"}'::jsonb, 'active', '2026-05-14'),
  ('sunday-roast-comedy-hackney', 'Sunday Roast Comedy', 'End your weekend right. A Sunday evening showcase with three acts and an MC in a Hackney pub. Good for acts wanting Sunday miles and punters who want one last laugh before Monday.', 'showcase', ARRAY['experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":0,"startTime":"19:00"}'::jsonb, '{"id":"sebright-arms-hackney","name":"Sebright Arms","address":"31-35 Coate St, London E2 9AG","area":"Hackney","nearestStation":"Bethnal Green","location":{"lat":51.5309,"lng":-0.0647}}'::jsonb, '{"entry":"£8","performerPay":"Expenses"}'::jsonb, '{"audience":"Pay on the door","performers":"Email to get on the bill"}'::jsonb, '{"instagram":"https://instagram.com/sundayroastcomedy"}'::jsonb, 'active', '2026-05-26'),
  ('friday-night-comedy-camden', 'Friday Night Comedy Camden', 'Camden''s weekly Friday-night club in a proper music venue. Big stage, big sound, big acts. If a name is doing a work-in-progress, this is where they try it out.', 'pro', ARRAY['pro']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":5,"startTime":"20:30"}'::jsonb, '{"id":"roundhouse-camden","name":"The Jazz Cafe","address":"5 Parkway, London NW1 7PG","area":"Camden","nearestStation":"Camden Town","location":{"lat":51.539,"lng":-0.142}}'::jsonb, '{"entry":"£18","performerPay":"Paid"}'::jsonb, '{"audience":"Book via their website","performers":"Agent bookings only"}'::jsonb, '{"website":"https://jazzcafe.co.uk","instagram":"https://instagram.com/jazzcafelondon"}'::jsonb, 'active', '2026-05-28'),
  ('open-mic-dalston', 'Dalston Open Mic', 'No-bringer, no-entry-fee open mic in East London. Run by a comedian for comedians. Small but loyal regular crowd who actually want to be there.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":3,"startTime":"20:00"}'::jsonb, '{"id":"victoria-dalston","name":"The Victoria","address":"451 Queensbridge Rd, London E8 3AS","area":"Dalston","nearestStation":"Dalston Junction","location":{"lat":51.5478,"lng":-0.0724}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free entry","performers":"Sign up on the night from 7:30pm"}'::jsonb, '{}'::jsonb, 'active', '2026-05-07'),
  ('the-little-comedy-room-wandsworth', 'The Little Comedy Room', 'Exactly what it says. A small room, a handful of acts, and an audience of maybe 40 people. The intimacy makes it either brilliant or brutal — usually brilliant.', 'open-mic', ARRAY['new','experienced']::text[], '{"required":false}'::jsonb, '{"frequency":"weekly","weekday":4,"startTime":"20:00"}'::jsonb, '{"id":"county-arms-wandsworth","name":"The County Arms","address":"345 Trinity Rd, London SW18 3SH","area":"Wandsworth","nearestStation":"Wandsworth Town","location":{"lat":51.4534,"lng":-0.1837}}'::jsonb, '{"entry":"Free","performerPay":"None"}'::jsonb, '{"audience":"Free, walk in","performers":"Email to get a slot"}'::jsonb, '{}'::jsonb, 'active', '2026-04-02')
